// SPEC QFLUSH QS3 — process.ts
// Rôle : Wrapper strict autour de child_process.spawn.
import { spawn } from 'node:child_process';
export function spawnStrict(state, name, command, options = {}) {
    const args = options.args ?? [];
    const cwd = options.cwd;
    const env = { ...process.env, ...(options.env || {}) };
    const child = spawn(command, args, { cwd, env, stdio: ['ignore', 'pipe', 'pipe'] });
    const info = {
        name,
        pid: child.pid ?? null,
        state: 'starting',
        restarts: 0,
        startedAt: Date.now(),
    };
    try {
        state.set(info);
    }
    catch { }
    if (child.stdout) {
        child.stdout.on('data', (d) => {
            try {
                console.log(`[${name}]`, d.toString());
            }
            catch { }
        });
    }
    if (child.stderr) {
        child.stderr.on('data', (d) => {
            try {
                console.warn(`[${name} ERROR]`, d.toString());
            }
            catch { }
        });
    }
    child.on('spawn', () => {
        try {
            state.update(name, { state: 'running', pid: child.pid ?? null });
        }
        catch { }
    });
    child.on('exit', (code) => {
        try {
            if (code === 0)
                state.update(name, { state: 'stopped', pid: null });
            else
                state.update(name, { state: 'error', lastError: code != null ? `exit:${code}` : 'exit', pid: null });
        }
        catch { }
    });
    child.on('error', (err) => {
        try {
            state.update(name, { state: 'error', lastError: String(err) });
        }
        catch { }
    });
    return child;
}
